function trackerFunc(send) {
  return function () {
    let prd_brand = '';
    let prd_code = '';
    let tab_name = '';
    let srch_kwd = '';

    if (
      location.pathname.match('product/detail') &&
      document.querySelector('.prod-item__display-name')
    ) {
      const prdel = document.querySelector('.prod-item__display-name').parentElement;
      prd_brand = prdel.querySelector('div > p')?.innerText || '';
      prd_code = location.href.split('/').pop();

    } else if (
      location.pathname.match('/search') &&
      document.querySelector('.search-result__tab')
    ) {
      tab_name =
        document.querySelector('button > div.is-selected > span')?.innerText || '';

      const inputEl = document.querySelector('.search-header__input');
      srch_kwd = inputEl?.value || inputEl?.placeholder || '';
    }

    setTimeout(() => {
      send({
        tag_code: "PV_DETAIL",
        event_type: "pageview",
        prd_code,
        prd_brand,
        tab_name,
        srch_kwd
      });
    }, 300);
  }
}

function trackerFunc(send) {
  return function (e) {
    const el = e.target.closest(
      "a, button, li, div, span, svg, [role=button]"
    );
    if (!el) return;

    send({
      tag_code: "COMMON_CLICK",
      event_type: "click",
      click_text: el.innerText?.trim().slice(0, 30) || '',
      class_name: el.className || '',
      tag: el.tagName
    });
  }
}

